(function(){
  function cleanPrice(p){
    let s = (p ?? '').toString().trim();
    if(s.includes('•')) s = s.split('•')[0].trim();
    s = s.replace(/\([^)]*\)/g, '').trim();
    if(s.includes('/')) s = s.split('/')[0].trim();
    s = s.replace(/\s+/g,' ').trim();
    return s;
  }

  const data = window.DEVICE_DATA || {};
  ['laptops','ipad'].forEach(function(key){
    const models = (data[key] && data[key].models) || [];
    models.forEach(function(m){
      (m.services||[]).forEach(function(sr){
        if(sr && typeof sr.price !== 'undefined'){
          sr.price = cleanPrice(sr.price);
        }
      });
    });
  });
})();
